// Author: abhinavkumarrath #include <bits/stdc++.h>using namespace std; #pragma GCC optimize("O3,unroll-loops")#pragma GCC target("avx2,bmi,bmi2,lzcnt,popcnt") using ll = long long;using vi = vector<int>;using vll = vector<ll>;using pii = pair<int, int>; #define pb push_back#define all(x) (x).begin(), (x).end()#define sz(x) (int)(x).size()#define fi first#define se second #define rep(i, a, b) for (int i = (a); i < (b); ++i)#define forn(i, n) rep(i, 0, n)#define per(i, a, b) for (int i = (b) - 1; i >= (a); --i)#define rofn(i, n) per(i, 0, n) template<class T> bool chmin(T& a, const T& b) { if (b < a) { a = b; return 1; } return 0; }template<class T> bool chmax(T& a, const T& b) { if (a < b) { a = b; return 1; } return 0; } void yes() { cout << "YES\n"; }void no() { cout << "NO\n"; } const int INF = 1e9;const ll LINF = 1e18; void solve() {    int n;    cin >> n;    vector<string> a(n);    forn(i, n) cin >> a[i];        vector<bool> s2(26 * 26, false);    vector<bool> s3(26 * 26 * 26, false);        bool ok = false;    forn(i, n) {        string s = a[i];        string rev = s;        reverse(all(rev));                if (s == rev) {            ok = true;            break;        }                if (sz(s) == 2) {            int r_idx = (rev[0] - 'a') * 26 + (rev[1] - 'a');            if (s2[r_idx]) ok = true;            forn(c, 26) {                if (s3[r_idx * 26 + c]) ok = true;            }            s2[(s[0] - 'a') * 26 + (s[1] - 'a')] = true;        } else if (sz(s) == 3) {            int r_idx = (rev[0] - 'a') * 26 * 26 + (rev[1] - 'a') * 26 + (rev[2] - 'a');            if (s3[r_idx]) ok = true;                        int r2_idx = (rev[0] - 'a') * 26 + (rev[1] - 'a');            if (s2[r2_idx]) ok = true;                        s3[(s[0] - 'a') * 26 * 26 + (s[1] - 'a') * 26 + (s[2] - 'a')] = true;        }                if (ok) break;    }        if (ok) yes();    else no();} int main() {    ios_base::sync_with_stdio(false);    cin.tie(nullptr);        int t = 1;    cin >> t;    while (t--) {        solve();    }    return 0;}